var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"MN No. FW000P5027-10\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n부록: 침식전 AB-014","JPN":"MN No. FW000P5027-10\\n<color=#ffd34c>1級要人</color>閲覧商人資料\\n付録：侵食戦AB-014","ENG":"MN No. FW000P5027-10\\n<color=#ffd34c>Clearance Level I</color> Classified Information\\nAnnex: Anti-Corruption War AB-014","TWN":"MN No.FW000P5027-10\\n<color=#ffd34c>1級要員</color> 閱覽審批資料\\n附錄侵蝕戰AB-014"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"3번 도로가 장악 당했습니다!","JPN":"3番道路を乗っ取られました！","ENG":"Road number 3 is compromised!","TWN":"3號道路被控制！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"예비대! 통신 두절!","JPN":"予備隊！　通信途絶！","ENG":"We've lost contact with the reserves! No comms!","TWN":"預備隊！通訊中斷！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"전방에 있던 기갑사단도 퇴각 중입니다. 이대로는 방어선을 유지할 수 없습니다. ","JPN":"先方の機甲師団も退却中です。このままでは、防御線を維持できません。 ","ENG":"The armored division is also retreating from the front lines. We won't be able to hold the line of defense at this rate. ","TWN":"前方的裝甲部隊也在撤退中，這樣下去無法維持防線。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"최악의 경우에는 전멸할 수도......","JPN":"最悪の場合、全滅する可能性も……","ENG":"If worst comes to worst... we may be facing extermination...","TWN":"最壞的情況可能會全軍覆沒……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"태스크포스는? 증원은 없나?","JPN":"タスクフォースカンパニーは？　増員はないのか？","ENG":"What about the TASKFORCE? Aren't they sending any reinforcements?","TWN":"特遣勢力呢？沒有增援嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"안토노프 대령의 부대가 호출에 응답하긴 했지만...... 세타 포인트에서 적 주력과 교전 중이라고 합니다.","JPN":"アントノフ大佐の部隊が呼び出しに応じましたが……\\nシータポイントで、敵の主力と交戦中だそうです。","ENG":"Colonel Antonov's unit did answer our call... But they're engaging the enemy's main effort at Theta Point.","TWN":"安東諾夫上校的部隊回應了求援……但是他們正在θ點與敵軍主力交戰。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"더 늦기 전에 퇴각하셔야 합니다.","JPN":"手遅れになる前に、退却すべきです。","ENG":"We must fall back before it's too late.","TWN":"我們必須在為時已晚前立刻撤退。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"......저기 저거 보이나?","JPN":"……あれが見えるか？","ENG":"You see that over there?","TWN":"……你看見那邊了嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"네?","JPN":"えっ？","ENG":"Sir?","TWN":"啊？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"저기 보호구역에 모여 있는 민간인들 말일세.","JPN":"あの保護区域に集まっている民間人を見ろ。","ENG":"I mean those civilians huddled up in the protection zone.","TWN":"我是說那邊聚集的平民們。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"우리가 도망치고 나면 저 사람들은 누가 지키나?","JPN":"俺たちが逃げたら、あの人たちは誰が守るんだ？","ENG":"Who's going to protect them if we flee?","TWN":"如果我們逃跑了誰來保護那些平民？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"But...","TWN":"這個……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"사단장님, 사단장님!","JPN":"指揮官、指揮官！","ENG":"Commander! Commander!","TWN":"長官，長官！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"뭔가?","JPN":"何だ？","ENG":"What is it?","TWN":"什麼事？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"퓨처 앳 워 소속의 연구원이라는 사람이 사단장님께 대면을 요청했습니다.","JPN":"フューチャーアットウォー所属の研究員と名乗る者が、指揮官に面談を要請しました。","ENG":"Some researcher from Future at War has requested a meeting with you.","TWN":"有個據說是隸屬於天啟兵器的研究員要求與您見面。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"상황을 타개하는 데 도움을 드릴 수 있다면서요.","JPN":"現状を打開するのに役立つはずだと言っています。","ENG":"They say they've got something that could pull us out of this rut.","TWN":"那個人說可以幫助我們。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"퓨처 앳 워?","JPN":"フューチャーアットウォー？","ENG":"Future at War?","TWN":"天啟兵器？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"그 왜, 연합군 전략 회의에 애들 장난감 같은 거 들고 나왔다던 놈들 아닙니까.","JPN":"えっと、確か……連合軍の戦略会議に、子供のオモチャのようなものを持ち込んだやつらです。","ENG":"You know, the nerds who brought those fancy toys at the combined forces' strategy meeting.","TWN":"為什麼？他們不是那些在聯軍戰略會議上掏出小朋友玩具的傢伙嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"그런데 너 어디 소속이야?","JPN":"お前、どこの所属だ？","ENG":"By the way, what's your unit, trooper?","TWN":"話說回來，你是哪個營的？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"지금이 어떤 상황인데 그런 작자들이 진지에 들락거려! 통제 똑바로 안 해!","JPN":"こんな状況で、やつらが陣地に入っていいわけないだろ！　何を考えてるんだ！","ENG":"How could you let some outsiders like that go in and out of our positions in a situation like this?! Keep your security in check!","TWN":"現在都什麼時候了，竟然讓可疑人員進出營地！還不好好管管！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"아니, 안으로 들여 보내.","JPN":"いや、ここへ通せ。","ENG":"No... Let them come see me.","TWN":"不，讓這個人進來吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"사단장님?!","JPN":"指揮官！？","ENG":"But sir?!","TWN":"長官？！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"지금 다 죽을 판국인데 무슨 짓인들 못하겠나.","JPN":"どうせ、このままでは全滅だ。試せるものは、すべて試すしかない。","ENG":"We're all about to kick the bucket anyway. I don't see why not.","TWN":"反正我們現在已經走投無路了，還有什麼不能做的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"잔말 말고 들여 보내게.","JPN":"さっさと通せ。","ENG":"Just let them in.","TWN":"別廢話了，快放那個人進來。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"아, 예!","JPN":"あ、はい！","ENG":"Uh... Yes, sir!","TWN":"啊，是！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"사실 그때는 반신반의하면서 수락했소.","JPN":"当時は半信半疑だった。","ENG":"To be honest, I had my doubts back then.","TWN":"其實，我那時也是半信半疑。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"물에 빠진 사람 지푸라기라도 잡는다지 않소. 사람들이 대피할 시간만 벌어 줘도 다행이겠거니 했지.","JPN":"藁にもすがるような思いだったな。\\n民間人が避難する時間を稼げるだけでも、上出来だと思っていた。","ENG":"I was grasping at straws, really. I thought it would've sufficed if they had bought us enough time to evacuate the civilians.","TWN":"畢竟溺水者會抓住任何一根浮木。我沒有抱太大期待，只希望能爭取時間讓平民們撤離。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그런데 상의가 끝난 지 몇 분 안 지나서, 그 연구원이 말한 결전병기가 도착했지.","JPN":"少し話した後、その研究員が言っていた決戦兵器が到着した。","ENG":"But only a few minutes after our discussion, that secret weapon the researcher mentioned arrived.","TWN":"但是會談結束沒幾分鐘，那位研究員說的決戰兵器就到了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"수송 헬기로도 옮기지 못할 만큼 크고 무거워서 탄도탄에나 쓰는 고체 로켓 부스터를 달고 날아오더군.","JPN":"輸送兵器でも運べないほど巨大な上に重く、弾道弾に使う個体ロケットブースターを装着させていたよ。","ENG":"It was so heavy that they couldn't airlift it with a chopper. Instead, it flew over here with solid fuel rocket boosters, the same they use for ballistic missiles.","TWN":"由於它太過巨大而且沉重，連運輸直升機都無法運輸，所以是由彈道導彈專用的固體助推器從空中運輸過來的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"주둔지에 착지할 때는 포탄이라도 떨어진 듯이 땅이 울렸어.","JPN":"それが飛んできて駐屯地に着地した時は、砲弾が落ちたかのように地面が轟いた。","ENG":"When it landed, it shook the ground as if we just took an artillery shell.","TWN":"它著陸時，大地如同受到炮擊般發出了悲鳴。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그리고...... 전선으로 <color=#ffd34c>걸어 나가서</color> 몰려오던 침식체들을 모조리 쓸어 버렸지.","JPN":"そして……戦線へ<color=#ffd34c>向かって行き、</color>押し寄せる侵食体を一掃した。","ENG":"And then... It <color=#ffd34c>walked</color> to the front lines and wiped out the swarms of C.O.s.","TWN":"然後……它就這樣 <color=#ffd34c>走到了</color> 最前線，把湧上來的侵蝕體全部消滅了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"나는 아직도 믿기지 않소.","JPN":"私はまだ信じられない。","ENG":"I still can't believe what I saw.","TWN":"我至今也無法相信。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"차원 함선도 그렇지만, 타이탄이 실존하는 병기라는 사실이......","JPN":"次元艦船もそうだが、タイタンが実在する兵器だという事実が……","ENG":"As if the dimension ships weren't incredible enough... the Titan actually exists?","TWN":"雖然我原本也不相信次元艦船的存在，但和泰坦比起來簡直小巫見大巫……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"내가 사관학교를 나올 때까지만 해도 그런 무기는 상상의 산물이었으니까.","JPN":"私が士官学校を卒業した時、そのような兵器は夢のような話だったからな。","ENG":"When I was in the military academy, weapons like that only existed in science fiction.","TWN":"畢竟我從軍校出來之前，那種武器都還只存在於想像中。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"하긴 그건 카운터도 마찬가진가......","JPN":"まあ、それはカウンターも一緒だが……","ENG":"Then again, I suppose the same could be said of Counters...","TWN":"說起來，就像制裁者一樣……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아무튼, 타이탄이 없었다면 우리는 물론 민간인들까지 그 곳에서 빠져나올 수 없었을 거요.","JPN":"とにかく、タイタンがいなかったら私たちはもちろん、民間人もあそこから脱出することができなかったはずだ。","ENG":"In any case, without the Titan, we wouldn't have been able to make it out of there, let alone save the civilians.","TWN":"總之，如果沒有泰坦，不要說我們，就連平民們都無法從那裡逃出來吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"나중에 들은 이야기지만, 그 연구원이 공문서를 위조해서 시험기를 반출한 거라고 하더군.","JPN":"後から聞いた話だが、その研究員は公文書を捏造して、テスト機を搬出したそうだ。","ENG":"I only heard this later, but it turns out that the researcher forged the paperwork to deploy the prototype.","TWN":"後來聽說，那個研究員是偽造了公文把試驗機搬出來的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그것 때문에 옷을 벗었다고 하던데......","JPN":"そのせいでクビになったと聞いたが……","ENG":"I heard she lost her job over that...","TWN":"而且還因為這件事丟了工作……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"다시 만날 수만 있다면, 꼭 감사 인사를 드리고 싶소.","JPN":"もう一度会えるなら、必ず礼を言いたい。","ENG":"If I could ever meet her again, I'd like to personally express my gratitude.","TWN":"如果能再次見面的話，我想好好表達我的感謝之意。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};